mapper.update:
update auth_refresh_token
set state = 'CONSUMED',
    pending_expires_at = null,
    revoked_at = #{now}
where token_hash = #{tokenHash}
  and state = 'ACTIVE'
  and revoked_at is null
  and expires_at > #{now}

update auth_refresh_token
set state = 'ACTIVE',
    pending_expires_at = null
where token_hash = #{tokenHash}
  and state = 'PENDING_ROTATION'
  and revoked_at is null
  and expires_at > #{now}
  and pending_expires_at <= #{now}

update auth_refresh_token
set state = 'PENDING_ROTATION',
    pending_expires_at = #{pendingExpiresAt}
where token_hash = #{tokenHash}
  and state = 'ACTIVE'
  and revoked_at is null
  and expires_at > #{now}
  and not exists (
      select 1 from auth_refresh_token_family_revocation where family_id = auth_refresh_token.family_id
  )

update auth_refresh_token
set state = 'CONSUMED',
    pending_expires_at = null,
    revoked_at = #{now}
where token_hash = #{tokenHash}
  and user_id = #{userId, jdbcType=BINARY}
  and family_id = #{familyId}
  and security_version = #{securityVersionAtIssue}
  and state = 'PENDING_ROTATION'
  and revoked_at is null
